import{_ as e,o as n,c as a,a4 as l}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"分子与细胞详解","description":"","frontmatter":{},"headers":[],"relativePath":"biology/cell.md","filePath":"biology/cell.md"}'),s={name:"biology/cell.md"};function r(i,t,o,d,g,p){return n(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="分子与细胞详解" tabindex="-1">分子与细胞详解 <a class="header-anchor" href="#分子与细胞详解" aria-label="Permalink to &quot;分子与细胞详解&quot;">​</a></h1><p><strong>走进生命的微观世界</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解细胞的分子组成</li><li>掌握细胞的结构和功能</li><li>理解细胞的代谢过程（光合作用和呼吸作用）⭐</li><li>了解细胞的生命历程</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分子与细胞</span></span>
<span class="line"><span>├── 细胞的分子组成</span></span>
<span class="line"><span>│   ├── 元素和化合物</span></span>
<span class="line"><span>│   ├── 蛋白质（重点）⭐</span></span>
<span class="line"><span>│   └── 核酸</span></span>
<span class="line"><span>├── 细胞的结构</span></span>
<span class="line"><span>│   ├── 细胞膜（流动镶嵌模型）⭐</span></span>
<span class="line"><span>│   ├── 细胞器</span></span>
<span class="line"><span>│   └── 细胞核</span></span>
<span class="line"><span>├── 细胞的代谢 ⭐</span></span>
<span class="line"><span>│   ├── 酶和ATP</span></span>
<span class="line"><span>│   ├── 细胞呼吸（有氧、无氧）⭐</span></span>
<span class="line"><span>│   └── 光合作用 ⭐</span></span>
<span class="line"><span>└── 细胞的生命历程</span></span>
<span class="line"><span>    ├── 细胞分裂（有丝分裂）⭐</span></span>
<span class="line"><span>    ├── 细胞分化</span></span>
<span class="line"><span>    └── 细胞衰老、凋亡、癌变</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：初中生物基础</li><li><strong>后续应用</strong>：遗传的细胞基础（减数分裂）、基因表达（转录翻译）</li><li><strong>跨学科联系</strong>：化学（有机化学）、物理（能量转换）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-细胞的分子组成" tabindex="-1">2.1 细胞的分子组成 <a class="header-anchor" href="#_2-1-细胞的分子组成" aria-label="Permalink to &quot;2.1 细胞的分子组成&quot;">​</a></h3><p><strong>大量元素</strong>：C、H、O、N、P、S、K、Ca、Mg（含量占生物体总重量万分之一以上） <strong>微量元素</strong>：Fe、Mn、Zn、Cu、B、Mo（含量少，但必不可少）</p><p><strong>最基本元素</strong>：C（碳）——生物大分子的骨架</p><p><strong>重要化合物</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">化合物</th><th style="text-align:center;">元素组成</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>水</strong></td><td style="text-align:center;">H、O</td><td style="text-align:left;">良好溶剂、参与反应、运输物质</td></tr><tr><td style="text-align:center;"><strong>无机盐</strong></td><td style="text-align:center;">多种</td><td style="text-align:left;">组成复杂化合物、维持生命活动</td></tr><tr><td style="text-align:center;"><strong>糖类</strong></td><td style="text-align:center;">C、H、O</td><td style="text-align:left;">主要能源物质</td></tr><tr><td style="text-align:center;"><strong>脂质</strong></td><td style="text-align:center;">C、H、O（有的含N、P）</td><td style="text-align:left;">储能、膜成分、调节</td></tr><tr><td style="text-align:center;"><strong>蛋白质</strong></td><td style="text-align:center;">C、H、O、N（有的含S）</td><td style="text-align:left;">生命活动的主要承担者</td></tr><tr><td style="text-align:center;"><strong>核酸</strong></td><td style="text-align:center;">C、H、O、N、P</td><td style="text-align:left;">遗传信息的携带者</td></tr></tbody></table><hr><h3 id="_2-2-蛋白质-⭐" tabindex="-1">2.2 蛋白质 ⭐ <a class="header-anchor" href="#_2-2-蛋白质-⭐" aria-label="Permalink to &quot;2.2 蛋白质 ⭐&quot;">​</a></h3><p><strong>基本单位</strong>：氨基酸（约20种）</p><p><strong>氨基酸结构通式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    H</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>H₂N-C-COOH</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    R（侧链基团）</span></span></code></pre></div><p><strong>氨基酸特点</strong>：至少含有一个氨基（-NH₂）和一个羧基（-COOH），且连在同一个碳原子上</p><p><strong>蛋白质的形成</strong>：</p><ul><li><strong>脱水缩合</strong>：一个氨基酸的羧基与另一个氨基酸的氨基连接，脱去一分子水</li><li><strong>肽键</strong>：-CO-NH-</li><li><strong>多肽链</strong>：多个氨基酸连接形成</li></ul><p><strong>相关计算</strong>：</p><ul><li>肽键数 = 氨基酸数 - 肽链数</li><li>蛋白质分子量 = 氨基酸总分子量 - 脱去水分子总分子量</li></ul><p><strong>蛋白质结构层次</strong>：</p><ol><li><strong>一级结构</strong>：氨基酸的排列顺序</li><li><strong>二级结构</strong>：肽链的局部折叠（如α-螺旋）</li><li><strong>三级结构</strong>：整条肽链的空间结构</li><li><strong>四级结构</strong>：多条肽链的组合</li></ol><p><strong>蛋白质功能多样性</strong>（结构决定功能）：</p><ul><li>结构蛋白（如肌肉蛋白、胶原蛋白）</li><li>功能蛋白：酶（催化）、抗体（免疫）、血红蛋白（运输）、胰岛素（调节）</li></ul><hr><h3 id="_2-3-核酸" tabindex="-1">2.3 核酸 <a class="header-anchor" href="#_2-3-核酸" aria-label="Permalink to &quot;2.3 核酸&quot;">​</a></h3><p><strong>分类</strong>：</p><ul><li><strong>DNA（脱氧核糖核酸）</strong>：主要存在于细胞核，双链双螺旋</li><li><strong>RNA（核糖核酸）</strong>：主要存在于细胞质，单链</li></ul><p><strong>基本单位</strong>：核苷酸</p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">DNA</th><th style="text-align:center;">RNA</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>五碳糖</strong></td><td style="text-align:center;">脱氧核糖</td><td style="text-align:center;">核糖</td></tr><tr><td style="text-align:center;"><strong>含氮碱基</strong></td><td style="text-align:center;">A、T、G、C</td><td style="text-align:center;">A、U、G、C</td></tr><tr><td style="text-align:center;"><strong>结构</strong></td><td style="text-align:center;">双螺旋</td><td style="text-align:center;">单链</td></tr><tr><td style="text-align:center;"><strong>分布</strong></td><td style="text-align:center;">主要在细胞核</td><td style="text-align:center;">主要在细胞质</td></tr><tr><td style="text-align:center;"><strong>功能</strong></td><td style="text-align:center;">储存遗传信息</td><td style="text-align:center;">传递遗传信息、参与蛋白质合成</td></tr></tbody></table><hr><h3 id="_2-4-细胞膜-⭐" tabindex="-1">2.4 细胞膜 ⭐ <a class="header-anchor" href="#_2-4-细胞膜-⭐" aria-label="Permalink to &quot;2.4 细胞膜 ⭐&quot;">​</a></h3><p><strong>流动镶嵌模型</strong>（桑格和尼克森提出）：</p><ul><li><strong>磷脂双分子层</strong>：基本支架，具有流动性</li><li><strong>蛋白质</strong>：镶嵌、贯穿、覆盖在磷脂双分子层上，承担运输、识别等功能</li><li><strong>糖类</strong>：与蛋白质或脂质结合形成糖蛋白或糖脂，参与细胞识别</li></ul><p><strong>结构特点</strong>：<strong>流动性</strong>（磷脂分子和大多数蛋白质分子可以运动）</p><p><strong>功能特性</strong>：<strong>选择透过性</strong>（控制物质进出）</p><p><strong>物质跨膜运输方式</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">运输方式</th><th style="text-align:center;">方向</th><th style="text-align:center;">是否需要载体</th><th style="text-align:center;">是否耗能</th><th style="text-align:center;">示例</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>自由扩散</strong></td><td style="text-align:center;">高→低</td><td style="text-align:center;">否</td><td style="text-align:center;">否</td><td style="text-align:center;">O₂、CO₂、水、甘油</td></tr><tr><td style="text-align:center;"><strong>协助扩散</strong></td><td style="text-align:center;">高→低</td><td style="text-align:center;">是</td><td style="text-align:center;">否</td><td style="text-align:center;">葡萄糖进入红细胞</td></tr><tr><td style="text-align:center;"><strong>主动运输</strong></td><td style="text-align:center;">低→高</td><td style="text-align:center;">是</td><td style="text-align:center;">是</td><td style="text-align:center;">小肠吸收葡萄糖、氨基酸</td></tr><tr><td style="text-align:center;"><strong>胞吞/胞吐</strong></td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">是</td><td style="text-align:center;">大分子物质（蛋白质）</td></tr></tbody></table><hr><h3 id="_2-5-细胞器" tabindex="-1">2.5 细胞器 <a class="header-anchor" href="#_2-5-细胞器" aria-label="Permalink to &quot;2.5 细胞器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">细胞器</th><th style="text-align:center;">结构特点</th><th style="text-align:center;">功能</th><th style="text-align:center;">分布</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>线粒体</strong></td><td style="text-align:center;">双层膜，内膜折叠成嵴</td><td style="text-align:center;">有氧呼吸主要场所，产生ATP</td><td style="text-align:center;">动植物细胞</td></tr><tr><td style="text-align:center;"><strong>叶绿体</strong></td><td style="text-align:center;">双层膜，内有类囊体</td><td style="text-align:center;">光合作用场所</td><td style="text-align:center;">植物绿色细胞</td></tr><tr><td style="text-align:center;"><strong>核糖体</strong></td><td style="text-align:center;">无膜，由rRNA和蛋白质组成</td><td style="text-align:center;">蛋白质合成场所</td><td style="text-align:center;">所有细胞</td></tr><tr><td style="text-align:center;"><strong>内质网</strong></td><td style="text-align:center;">单层膜，网状</td><td style="text-align:center;">蛋白质加工、脂质合成</td><td style="text-align:center;">动植物细胞</td></tr><tr><td style="text-align:center;"><strong>高尔基体</strong></td><td style="text-align:center;">单层膜，扁平囊状</td><td style="text-align:center;">蛋白质加工、分类、包装</td><td style="text-align:center;">动植物细胞</td></tr><tr><td style="text-align:center;"><strong>溶酶体</strong></td><td style="text-align:center;">单层膜，含水解酶</td><td style="text-align:center;">分解衰老细胞器、吞噬病原体</td><td style="text-align:center;">动物细胞</td></tr><tr><td style="text-align:center;"><strong>液泡</strong></td><td style="text-align:center;">单层膜，含细胞液</td><td style="text-align:center;">储存物质、维持细胞形态</td><td style="text-align:center;">植物细胞</td></tr><tr><td style="text-align:center;"><strong>中心体</strong></td><td style="text-align:center;">无膜，由两个中心粒组成</td><td style="text-align:center;">与细胞分裂有关</td><td style="text-align:center;">动物细胞、低等植物</td></tr></tbody></table><p><strong>分泌蛋白的合成和分泌路径</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>核糖体（合成肽链）→ 内质网（加工）→ 囊泡 → 高尔基体（再加工）→ 囊泡 → 细胞膜（分泌）</span></span>
<span class="line"><span>                     ↑_________________________________________↓</span></span>
<span class="line"><span>                                （线粒体供能）</span></span></code></pre></div><hr><h3 id="_2-6-细胞代谢-⭐" tabindex="-1">2.6 细胞代谢 ⭐ <a class="header-anchor" href="#_2-6-细胞代谢-⭐" aria-label="Permalink to &quot;2.6 细胞代谢 ⭐&quot;">​</a></h3><h4 id="_2-6-1-酶" tabindex="-1">2.6.1 酶 <a class="header-anchor" href="#_2-6-1-酶" aria-label="Permalink to &quot;2.6.1 酶&quot;">​</a></h4><p><strong>本质</strong>：活细胞产生的具有催化作用的有机物，绝大多数是蛋白质，少数是RNA</p><p><strong>特性</strong>：</p><ul><li><strong>高效性</strong>：催化效率远高于无机催化剂</li><li><strong>专一性</strong>：一种酶只能催化一种或一类反应</li><li><strong>作用条件温和</strong>：需要适宜的温度和pH</li></ul><p><strong>影响酶活性的因素</strong>：</p><ul><li><strong>温度</strong>：低温抑制活性，高温使酶失活（变性）</li><li><strong>pH</strong>：过酸或过碱使酶失活</li></ul><p><strong>酶活性曲线</strong>：</p><ul><li>温度-pH曲线：倒U形，最适温度/pH时活性最高</li></ul><hr><h4 id="_2-6-2-atp" tabindex="-1">2.6.2 ATP <a class="header-anchor" href="#_2-6-2-atp" aria-label="Permalink to &quot;2.6.2 ATP&quot;">​</a></h4><p><strong>结构</strong>：腺苷（腺嘌呤+核糖）+ 三个磷酸基团</p><p><strong>功能</strong>：直接能源物质</p><p><strong>ATP与ADP的相互转化</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ATP ⇌ ADP + Pi + 能量</span></span></code></pre></div><ul><li>水解：释放能量，供生命活动</li><li>合成：储存能量，来自光合作用或细胞呼吸</li></ul><p><strong>注意</strong>：这不是可逆反应（酶不同、场所不同、能量来源不同）</p><hr><h4 id="_2-6-3-细胞呼吸-⭐" tabindex="-1">2.6.3 细胞呼吸 ⭐ <a class="header-anchor" href="#_2-6-3-细胞呼吸-⭐" aria-label="Permalink to &quot;2.6.3 细胞呼吸 ⭐&quot;">​</a></h4><p><strong>概念</strong>：有机物在细胞内经过一系列的氧化分解，生成CO₂或其他产物，释放能量并合成ATP的过程</p><p><strong>有氧呼吸</strong>（主要场所：线粒体）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">阶段</th><th style="text-align:center;">场所</th><th style="text-align:center;">反应物</th><th style="text-align:center;">产物</th><th style="text-align:center;">能量变化</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一阶段</strong></td><td style="text-align:center;">细胞质基质</td><td style="text-align:center;">葡萄糖</td><td style="text-align:center;">丙酮酸 + [H]</td><td style="text-align:center;">少量ATP</td></tr><tr><td style="text-align:center;"><strong>第二阶段</strong></td><td style="text-align:center;">线粒体基质</td><td style="text-align:center;">丙酮酸 + H₂O</td><td style="text-align:center;">CO₂ + [H]</td><td style="text-align:center;">少量ATP</td></tr><tr><td style="text-align:center;"><strong>第三阶段</strong></td><td style="text-align:center;">线粒体内膜</td><td style="text-align:center;">[H] + O₂</td><td style="text-align:center;">H₂O</td><td style="text-align:center;">大量ATP</td></tr></tbody></table><p><strong>总反应式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C₆H₁₂O₆ + 6H₂O + 6O₂ → 6CO₂ + 12H₂O + 能量</span></span></code></pre></div><p><strong>无氧呼吸</strong>（场所：细胞质基质）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:center;">生物</th><th style="text-align:center;">产物</th><th style="text-align:center;">反应式</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>酒精发酵</strong></td><td style="text-align:center;">大多数植物、酵母菌</td><td style="text-align:center;">酒精 + CO₂</td><td style="text-align:center;">C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂ + 少量能量</td></tr><tr><td style="text-align:center;"><strong>乳酸发酵</strong></td><td style="text-align:center;">动物、乳酸菌、少数植物</td><td style="text-align:center;">乳酸</td><td style="text-align:center;">C₆H₁₂O₆ → 2C₃H₆O₃ + 少量能量</td></tr></tbody></table><p><strong>有氧呼吸vs无氧呼吸比较</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">比较项目</th><th style="text-align:center;">有氧呼吸</th><th style="text-align:center;">无氧呼吸</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>条件</strong></td><td style="text-align:center;">需O₂</td><td style="text-align:center;">不需O₂</td></tr><tr><td style="text-align:center;"><strong>场所</strong></td><td style="text-align:center;">细胞质基质、线粒体</td><td style="text-align:center;">细胞质基质</td></tr><tr><td style="text-align:center;"><strong>产物</strong></td><td style="text-align:center;">CO₂、H₂O</td><td style="text-align:center;">酒精+CO₂或乳酸</td></tr><tr><td style="text-align:center;"><strong>能量释放</strong></td><td style="text-align:center;">大量</td><td style="text-align:center;">少量</td></tr><tr><td style="text-align:center;"><strong>是否彻底分解</strong></td><td style="text-align:center;">是</td><td style="text-align:center;">否</td></tr></tbody></table><hr><h4 id="_2-6-4-光合作用-⭐" tabindex="-1">2.6.4 光合作用 ⭐ <a class="header-anchor" href="#_2-6-4-光合作用-⭐" aria-label="Permalink to &quot;2.6.4 光合作用 ⭐&quot;">​</a></h4><p><strong>概念</strong>：绿色植物通过叶绿体，利用光能，把CO₂和H₂O转化成储存能量的有机物，并释放O₂的过程</p><p><strong>光反应</strong>（场所：类囊体薄膜）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水的光解：H₂O → [H] + O₂（需要光）</span></span>
<span class="line"><span>ATP合成：ADP + Pi + 光能 → ATP</span></span></code></pre></div><ul><li>条件：光、色素、酶</li><li>产物：[H]（NADPH）、ATP、O₂</li></ul><p><strong>暗反应</strong>（场所：叶绿体基质）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CO₂固定：CO₂ + C₅ → 2C₃</span></span>
<span class="line"><span>C₃还原：2C₃ + [H] + ATP → (CH₂O) + C₅</span></span></code></pre></div><ul><li>条件：酶、[H]、ATP</li><li>产物：有机物(CH₂O)、C₅（再生）</li></ul><p><strong>光合作用总反应式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CO₂ + H₂O → (CH₂O) + O₂（条件：光能、叶绿体）</span></span></code></pre></div><p><strong>光合作用与细胞呼吸的关系</strong>：</p><ul><li>光合作用：合成有机物，储存能量</li><li>细胞呼吸：分解有机物，释放能量</li><li>二者相互依存，共同维持生命活动</li></ul><hr><h3 id="_2-7-细胞的生命历程" tabindex="-1">2.7 细胞的生命历程 <a class="header-anchor" href="#_2-7-细胞的生命历程" aria-label="Permalink to &quot;2.7 细胞的生命历程&quot;">​</a></h3><h4 id="_2-7-1-有丝分裂-⭐" tabindex="-1">2.7.1 有丝分裂 ⭐ <a class="header-anchor" href="#_2-7-1-有丝分裂-⭐" aria-label="Permalink to &quot;2.7.1 有丝分裂 ⭐&quot;">​</a></h4><p><strong>过程</strong>（以植物细胞为例）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">时期</th><th style="text-align:left;">主要特征</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>间期</strong></td><td style="text-align:left;">DNA复制，有关蛋白质合成，细胞适度生长</td></tr><tr><td style="text-align:center;"><strong>前期</strong></td><td style="text-align:left;">核膜、核仁消失，染色体、纺锤体出现</td></tr><tr><td style="text-align:center;"><strong>中期</strong></td><td style="text-align:left;">染色体着丝点排列在赤道板上，形态最清晰</td></tr><tr><td style="text-align:center;"><strong>后期</strong></td><td style="text-align:left;">着丝点分裂，姐妹染色单体分开，染色体数目加倍</td></tr><tr><td style="text-align:center;"><strong>末期</strong></td><td style="text-align:left;">核膜、核仁重现，染色体、纺锤体消失，细胞板形成</td></tr></tbody></table><p><strong>特点</strong>：亲代细胞染色体复制后，平均分配到两个子细胞中，子细胞与亲代细胞染色体数目相同</p><p><strong>意义</strong>：保持亲子代细胞遗传信息的一致性</p><hr><h4 id="_2-7-2-细胞分化" tabindex="-1">2.7.2 细胞分化 <a class="header-anchor" href="#_2-7-2-细胞分化" aria-label="Permalink to &quot;2.7.2 细胞分化&quot;">​</a></h4><p><strong>概念</strong>：在个体发育中，由一个或一种细胞增殖产生的后代，在形态、结构和功能上发生稳定性差异的过程</p><p><strong>实质</strong>：<strong>基因的选择性表达</strong>（不同细胞表达的基因不同）</p><p><strong>特点</strong>：</p><ul><li>普遍性：多细胞生物普遍存在</li><li>持久性：贯穿生命全过程</li><li>稳定性：一般不可逆转</li><li>不可逆性：分化后的细胞一般不能再分化成其他细胞</li></ul><hr><h4 id="_2-7-3-细胞衰老、凋亡、癌变" tabindex="-1">2.7.3 细胞衰老、凋亡、癌变 <a class="header-anchor" href="#_2-7-3-细胞衰老、凋亡、癌变" aria-label="Permalink to &quot;2.7.3 细胞衰老、凋亡、癌变&quot;">​</a></h4><p><strong>细胞衰老特征</strong>：</p><ul><li>水分减少，细胞萎缩</li><li>酶活性降低，代谢减慢</li><li>色素积累</li><li>细胞膜通透性改变</li><li>细胞核体积增大，核膜内折</li></ul><p><strong>细胞凋亡</strong>：</p><ul><li>概念：由基因决定的细胞自动结束生命的过程（细胞编程性死亡）</li><li>意义：完成正常发育，维持内部环境稳定，抵御外界干扰</li></ul><p><strong>细胞癌变</strong>：</p><ul><li>特征：无限增殖、形态结构改变、易分散转移</li><li>原因：原癌基因和抑癌基因发生突变</li></ul><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-蛋白质相关计算" tabindex="-1">例题1：蛋白质相关计算 <a class="header-anchor" href="#例题1-蛋白质相关计算" aria-label="Permalink to &quot;例题1：蛋白质相关计算&quot;">​</a></h3><p><strong>题目</strong>：某蛋白质由n条肽链组成，共有m个氨基酸，求：</p><ul><li>(1) 肽键数</li><li>(2) 脱去水分子数</li><li>(3) 若氨基酸平均分子量为a，求蛋白质分子量</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 肽键数 = 氨基酸数 - 肽链数 = m - n</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 脱去水分子数 = 肽键数 = m - n</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(3) 蛋白质分子量 = 氨基酸总分子量 - 脱去水分子总分子量</span></span>
<span class="line"><span>                  = m·a - (m-n)·18</span></span></code></pre></div><hr><h3 id="例题2-物质跨膜运输判断" tabindex="-1">例题2：物质跨膜运输判断 <a class="header-anchor" href="#例题2-物质跨膜运输判断" aria-label="Permalink to &quot;例题2：物质跨膜运输判断&quot;">​</a></h3><p><strong>题目</strong>：下列物质通过细胞膜的方式分别是？</p><ul><li>(1) O₂进入肺泡细胞</li><li>(2) 葡萄糖进入红细胞</li><li>(3) K⁺进入植物根细胞</li><li>(4) 蛋白质分泌到细胞外</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 自由扩散（O₂是小分子，顺浓度梯度）</span></span>
<span class="line"><span>(2) 协助扩散（需要载体，顺浓度梯度，不耗能）</span></span>
<span class="line"><span>(3) 主动运输（逆浓度梯度，需要载体和能量）</span></span>
<span class="line"><span>(4) 胞吐（大分子，通过囊泡分泌）</span></span></code></pre></div><hr><h3 id="例题3-光合作用和呼吸作用计算" tabindex="-1">例题3：光合作用和呼吸作用计算 <a class="header-anchor" href="#例题3-光合作用和呼吸作用计算" aria-label="Permalink to &quot;例题3：光合作用和呼吸作用计算&quot;">​</a></h3><p><strong>题目</strong>：某植物在黑暗条件下释放CO₂ 6mg/h，在光照条件下（光合速率大于呼吸速率）吸收CO₂ 18mg/h。求：</p><ul><li>(1) 呼吸速率</li><li>(2) 总光合速率</li><li>(3) 净光合速率</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 呼吸速率 = 6 mg CO₂/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 总光合速率 = 净光合速率 + 呼吸速率</span></span>
<span class="line"><span>               = 18 + 6 </span></span>
<span class="line"><span>               = 24 mg CO₂/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(3) 净光合速率 = 18 mg CO₂/h（题目给出）</span></span></code></pre></div><p><strong>关系</strong>：总光合速率 = 净光合速率 + 呼吸速率</p><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：某蛋白质有100个氨基酸，形成2条肽链，求肽键数和脱去水分子数。</p><p><strong>练习2</strong>：DNA和RNA在化学组成上的区别是什么？</p><p><strong>练习3</strong>：画出有氧呼吸三个阶段的流程图。</p><p><strong>练习4</strong>：比较光反应和暗反应的场所、条件、产物。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：肽键数=98，脱去水分子数=98</li><li>练习2：五碳糖不同（脱氧核糖vs核糖），碱基不同（T vs U）</li><li>练习3：见上文表格</li><li>练习4：见上文表格</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：某植物在25℃、光照强度为X时，光合速率达到最大。分析：</p><ul><li>(1) 若温度升高到35℃，光合速率如何变化？为什么？</li><li>(2) 若光照强度增加到2X，光合速率如何变化？为什么？</li></ul><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-蛋白质计算总是错" tabindex="-1">FAQ 1：蛋白质计算总是错 <a class="header-anchor" href="#faq-1-蛋白质计算总是错" aria-label="Permalink to &quot;FAQ 1：蛋白质计算总是错&quot;">​</a></h3><p><strong>常见错误</strong>：</p><ul><li>忘记减去肽链数</li><li>忘记水的分子量是18</li><li>环状肽的特殊计算</li></ul><p><strong>记忆方法</strong>：</p><ul><li>&quot;手拉手&quot;：n个人手拉手，形成n-1个连接</li><li>环状肽：n个人围成圈，形成n个连接</li></ul><hr><h3 id="faq-2-细胞器的功能总记混" tabindex="-1">FAQ 2：细胞器的功能总记混 <a class="header-anchor" href="#faq-2-细胞器的功能总记混" aria-label="Permalink to &quot;FAQ 2：细胞器的功能总记混&quot;">​</a></h3><p><strong>分类记忆</strong>：</p><ul><li><strong>与能量有关</strong>：线粒体（细胞呼吸）、叶绿体（光合作用）</li><li><strong>与蛋白质有关</strong>：核糖体（合成）、内质网（加工）、高尔基体（再加工）</li><li><strong>其他</strong>：溶酶体（分解）、液泡（储存）、中心体（分裂）</li></ul><hr><h3 id="faq-3-光合作用和呼吸作用过程理不清" tabindex="-1">FAQ 3：光合作用和呼吸作用过程理不清 <a class="header-anchor" href="#faq-3-光合作用和呼吸作用过程理不清" aria-label="Permalink to &quot;FAQ 3：光合作用和呼吸作用过程理不清&quot;">​</a></h3><p><strong>建议</strong>：</p><ol><li>画流程图，贴在显眼位置</li><li>分阶段记忆，不要一次记全部</li><li>理解&quot;光反应为暗反应提供[H]和ATP&quot;</li><li>定期复述流程</li></ol><p><strong>关键节点</strong>：</p><ul><li>水光解 → [H] + O₂</li><li>CO₂固定 → C₃</li><li>C₃还原 → 需要[H]和ATP</li></ul><hr><h3 id="faq-4-有丝分裂各期特点记不住" tabindex="-1">FAQ 4：有丝分裂各期特点记不住 <a class="header-anchor" href="#faq-4-有丝分裂各期特点记不住" aria-label="Permalink to &quot;FAQ 4：有丝分裂各期特点记不住&quot;">​</a></h3><p><strong>口诀</strong>：</p><ul><li>&quot;前期膜仁消失现两体&quot;（核膜核仁消失，染色体纺锤体出现）</li><li>&quot;中期形定数晰赤道齐&quot;（染色体形态固定，数目清晰，排列在赤道板）</li><li>&quot;后期点裂数加均两极&quot;（着丝点分裂，染色体数目加倍，移向两极）</li><li>&quot;末期两消两现重开始&quot;（染色体纺锤体消失，核膜核仁重现）</li></ul><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 能说出细胞中主要化合物的元素组成和功能</li><li>[ ] 能解释蛋白质结构多样性的原因</li><li>[ ] 能进行蛋白质相关计算</li><li>[ ] 能区分DNA和RNA的结构和功能</li><li>[ ] 能理解细胞膜流动镶嵌模型的主要内容</li><li>[ ] 能判断不同物质的跨膜运输方式</li><li>[ ] 能说出主要细胞器的功能</li><li>[ ] 能画出水光解和暗反应的详细过程</li><li>[ ] 能画出水氧呼吸三个阶段的流程图</li><li>[ ] 能进行光合作用和呼吸作用的相关计算</li><li>[ ] 能描述有丝分裂各时期的特点</li><li>[ ] 能理解细胞分化的实质</li></ul><hr><p><strong>文档编号</strong>: Bio-Learn-Detail-001<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,173)])])}const x=e(s,[["render",r]]);export{h as __pageData,x as default};
